<section class="account-page shell section-space-small"><div class="account-head"><p class="eyebrow">COMANDĂ</p><h1><?= e($order['order_number']) ?></h1><p>Plasată la <?= date('d.m.Y H:i',strtotime($order['created_at'])) ?></p></div><div class="account-layout"><?php require BASE_PATH.'/app/Views/account/nav.php'; ?><div class="account-content"><section class="account-panel"><h2>Produsele comandate</h2><?php foreach($items as $item): ?><div class="order-item-line"><span><strong><?= e($item['name_snapshot']) ?></strong><small><?= e($item['sku_snapshot']) ?> · <?= (int)$item['quantity'] ?> buc.</small></span><b><?= money($item['total_minor']) ?></b></div><?php endforeach; ?><div class="summary-total"><span>Total</span><strong><?= money($order['grand_total_minor']) ?></strong></div></section><section class="account-panel"><h2>Parcursul comenzii</h2><ol class="timeline"><?php foreach($history as $event): ?><li><strong><?= e($event['public_label']) ?></strong><p><?= e($event['public_message']) ?></p><time><?= date('d.m.Y H:i',strtotime($event['created_at'])) ?></time></li><?php endforeach; ?></ol><?php if($shipment&&$shipment['awb']): ?><a class="button button-outline" href="<?= e($shipment['tracking_url']) ?>">Urmărește AWB <?= e($shipment['awb']) ?></a><?php endif; ?></section></div></div></section>

